//! Generate the workspace's `compose.yaml`.
//!
//! The workspace compose file is now **dev-only**: it brings up
//! the moon-ide shell container and nothing else. Project services
//! (a folder's own `docker-compose.yml`) run as **separate compose
//! projects** managed per folder — see [`crate::project_compose`]
//! and the
//! [ADR 0007 amendment](../../../specs/decisions/0007-compose-and-moon-base.md#amendment-2026-04-29--workspace-shell-vs-project-services)
//! for why we split the two.
//!
//! Output shape:
//!
//! ```yaml
//! # Generated by moon-ide. Mounts come from bound-folders.json;
//! # project services live in each folder's own docker-compose.yml
//! # and are managed per-folder, not from this file.
//!
//! name: moon-ws-default
//!
//! services:
//!   dev:
//!     image: moon-base:dev
//!     init: true
//!     working_dir: /workspace
//!     volumes:
//!       - /home/me/code/moon-landing:/workspace/moon-landing
//!       - /home/me/code/moon-ide:/workspace/moon-ide
//!     command: ["sleep", "infinity"]
//!
//! x-moon:
//!   shell-service: dev
//! ```
//!
//! Path strategy: the compose file lives at
//! `~/.local/share/moon-ide/workspaces/<id>/compose.yaml` —
//! outside any specific repo, so every bind-mount path is the
//! absolute host path verbatim.
//!
//! Why a string template, not `serde_yaml`
//! ----------------------------------------
//!
//! The `serde_yaml` crate has been unmaintained since late 2023
//! and the structure we emit is small + fixed. Hand-rendered we
//! get exact control over comments, key order, and whitespace —
//! the file is meant to be human-readable, not parsed back by us.
//! If a future need to read it back appears we'll reach for a
//! maintained YAML crate at that point, not preemptively.

use std::fmt::Write as _;

use camino::Utf8PathBuf;

use crate::project::ProjectName;

/// One folder mounted into the dev container.
///
/// `mount_name` is the segment placed under `/workspace/`; for a
/// folder at `/home/me/code/moon-landing` it'll be
/// `moon-landing`. Callers are responsible for mount-name
/// uniqueness within a workspace (the registry layer is the
/// natural enforcement point — see
/// [`specs/roadmaps/phase-02-containers.md`](../../../specs/roadmaps/phase-02-containers.md#pending-redesign-workspace--folder)).
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct BoundMount {
	/// Absolute host-side path. Written verbatim into `volumes:`.
	pub host_path: Utf8PathBuf,
	/// Container-side directory name (the basename portion of
	/// `/workspace/<name>`). Validated by the caller — this layer
	/// trusts the input.
	pub mount_name: String,
}

/// SSH agent forwarding into the dev container.
///
/// Bind-mounts the host's SSH agent socket inside the container
/// at a fixed path and points `SSH_AUTH_SOCK` at it, so
/// `git fetch`, `gh auth ...`, and any other SSH-using tool the
/// user runs in a container terminal can reach the host's keys
/// without copying private material into the container.
///
/// Source path is resolved at the lifecycle layer:
///
/// - **macOS (Docker Desktop)** uses the magic
///   `/run/host-services/ssh-auth.sock` — Docker Desktop
///   special-cases that path and forwards it to the host's
///   running agent.
/// - **Linux** uses `$SSH_AUTH_SOCK` if it's set and the socket
///   exists, otherwise we skip the forward entirely (a
///   `tracing::warn!` flags the silent skip; the rest of the
///   container still works, just without the agent).
///
/// In-container path is the same regardless of platform — we
/// re-use Docker Desktop's convention so any tooling that
/// already understands it Just Works inside the workspace shell.
pub const SSH_AGENT_CONTAINER_PATH: &str = "/run/host-services/ssh-auth.sock";

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SshAgentForward {
	/// Absolute host-side path to the SSH agent's unix socket.
	pub host_socket: Utf8PathBuf,
}

/// In-container path the host's `gh` config is mounted at. We
/// pin it to the `dev` user's `~/.config/gh` so the in-container
/// `gh` finds the host's auth without needing
/// `GH_CONFIG_DIR=/whatever` on every invocation. `dev`'s home is
/// `/home/dev` per the moon-base Dockerfile.
pub const GH_CONFIG_CONTAINER_PATH: &str = "/home/dev/.config/gh";

/// Bind-mount of the host's `gh` config directory (typically
/// `~/.config/gh`) into the dev container, read-only. Surfaces
/// the host's existing `gh auth login` session as the container's
/// auth state — opening a container terminal and running
/// `gh pr list` Just Works without re-authing.
///
/// Read-only on purpose:
///
/// 1. **One source of truth.** The host owns the auth; the
///    container reads it. A container `gh auth login` would
///    silently update the host's config (because the bind mount
///    is shared), which is surprising and hard to undo.
/// 2. **No accidental mutation.** Tools that lazily write the
///    config (e.g. `gh config set`) fail loudly inside the
///    container instead of mutating host state.
/// 3. **Mirrors SSH agent forwarding.** The agent socket is
///    similarly host-owned; gh config follows the same pattern.
///
/// If the host config doesn't exist yet (`~/.config/gh` is
/// absent because the user has never run `gh auth login`), the
/// lifecycle layer skips the mount entirely — Docker would
/// otherwise auto-create the source as a directory and shadow
/// any later host login until the container is recreated.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct GhConfigMount {
	/// Absolute host-side path to the gh config directory.
	pub host_path: Utf8PathBuf,
}

/// The host's `git config --global user.{name,email}`, projected
/// into the dev container as `GIT_AUTHOR_*` / `GIT_COMMITTER_*`
/// environment variables.
///
/// Why env vars and not a mounted `~/.gitconfig`:
///
/// 1. **Surgical surface.** We only export the bits we know we
///    want (the identity). A mounted host gitconfig would also
///    drag in credential helpers, signing settings, and per-tool
///    aliases — most of which point at host-only binaries that
///    don't exist in the container and surface as confusing
///    `git config --get` errors.
/// 2. **Layered safely.** Env vars take precedence over
///    `~/.gitconfig` inside the container, so the dev's own
///    in-container gitconfig (if they ever set one) keeps
///    working. The environment is the override, not a
///    replacement.
/// 3. **Easy to reason about.** A glance at the generated
///    `compose.yaml` shows exactly which identity the container
///    will commit as.
///
/// Resolved at the lifecycle layer — see
/// [`crate::lifecycle::detect_host_git_identity`]. `None` (no
/// global identity configured) skips the four env vars entirely;
/// the container's git is then in the same "Please tell me who
/// you are" state it'd have on a fresh checkout, which is the
/// correct fallback (we'd rather refuse to commit than commit as
/// the wrong person).
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct HostGitIdentity {
	pub name: String,
	pub email: String,
}

/// How the generator should populate the `dev` service.
#[derive(Debug, Clone)]
pub struct ComposeRenderOptions<'a> {
	/// `name:` value — the compose project identifier; see
	/// [`crate::project`].
	pub project: &'a ProjectName,
	/// Image reference for the `dev` service. While moon-base is
	/// in tree but unpublished we default callers to
	/// `moon-base:dev` (a local build). Once a published tag
	/// exists this'll move to `huggingface/moon-base:<tag>`.
	pub dev_image: &'a str,
	/// Bind-mount entries for the `dev` service. Empty is fine
	/// — we still emit `volumes: []` (compose tolerates it) so
	/// the generator's output is consistent. In practice the IDE
	/// only writes this file once at least one folder is bound.
	pub bound_mounts: &'a [BoundMount],
	/// Optional SSH agent forwarding. `None` skips the volume
	/// and environment block entirely (no `SSH_AUTH_SOCK` set
	/// inside the container, no agent socket mounted).
	pub ssh_agent: Option<&'a SshAgentForward>,
	/// Optional git identity carried over from the host. `None`
	/// leaves the container's git unconfigured, so the first
	/// commit prompts "Please tell me who you are" — a deliberate
	/// "refuse rather than commit as the wrong person" fallback.
	pub git_identity: Option<&'a HostGitIdentity>,
	/// Optional host `gh` config bind mount. `None` skips the
	/// volume entirely (no auth pass-through; `gh` inside the
	/// container is in its default unauthenticated state).
	pub gh_config: Option<&'a GhConfigMount>,
}

/// Wrap `value` in double quotes, escaping `\` and `"` so an
/// arbitrary user string (a name with quotes, an email with a
/// `@`, anything containing `:` / `#` / leading whitespace) is
/// always YAML-safe. Cheaper than pulling in a YAML escaper for
/// the few env values we ever emit; matches the YAML 1.2 quoted
/// scalar rules we actually need.
fn quote_yaml_double(value: &str) -> String {
	let mut out = String::with_capacity(value.len() + 2);
	out.push('"');
	for ch in value.chars() {
		match ch {
			'\\' => out.push_str("\\\\"),
			'"' => out.push_str("\\\""),
			'\n' => out.push_str("\\n"),
			'\t' => out.push_str("\\t"),
			'\r' => out.push_str("\\r"),
			c => out.push(c),
		}
	}
	out.push('"');
	out
}

/// Result of [`generate_compose`].
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ComposeRender {
	/// The full file contents, ready to be written to
	/// `<state_dir>/compose.yaml`.
	pub yaml: String,
}

/// Render the workspace's `compose.yaml`.
pub fn generate_compose(options: ComposeRenderOptions<'_>) -> ComposeRender {
	let mut yaml = String::new();
	let _ = writeln!(yaml, "# Generated by moon-ide. Mounts come from bound-folders.json;");
	let _ = writeln!(yaml, "# project services live in each folder's own docker-compose.yml");
	let _ = writeln!(yaml, "# and are managed per-folder, not from this file.");
	let _ = writeln!(yaml, "#");
	let _ = writeln!(yaml, "# Architecture: see specs/containers.md in the moon-ide");
	let _ = writeln!(yaml, "# repository.");
	let _ = writeln!(yaml);

	let _ = writeln!(yaml, "name: {}", options.project);
	let _ = writeln!(yaml);

	let _ = writeln!(yaml, "services:");
	let _ = writeln!(yaml, "  dev:");
	let _ = writeln!(yaml, "    image: {}", options.dev_image);
	// `init: true` reaps zombie processes for tools like watch
	// loops and `bun install`'s child workers — the same reason
	// `tini` ships in most "polyglot dev shell" base images.
	let _ = writeln!(yaml, "    init: true");
	let _ = writeln!(yaml, "    working_dir: /workspace");
	let _ = writeln!(yaml, "    volumes:");
	if options.bound_mounts.is_empty() && options.ssh_agent.is_none() && options.gh_config.is_none() {
		// Empty list is valid YAML and compose accepts it; this
		// keeps the structure consistent for the no-folder /
		// no-ssh-agent / no-gh-config edge case.
		let _ = writeln!(yaml, "      []");
	} else {
		for mount in options.bound_mounts {
			let _ = writeln!(
				yaml,
				"      - {host}:/workspace/{name}",
				host = mount.host_path.as_str(),
				name = mount.mount_name,
			);
		}
		if let Some(agent) = options.ssh_agent {
			// Bind the host's SSH agent socket so `git fetch`,
			// `gh`, etc. inside the container reach the host's
			// keys without copying any private material.
			let _ = writeln!(
				yaml,
				"      - {host}:{container}",
				host = agent.host_socket.as_str(),
				container = SSH_AGENT_CONTAINER_PATH,
			);
		}
		if let Some(gh) = options.gh_config {
			// Read-only by design — the container reads the
			// host's auth, never writes back.
			let _ = writeln!(
				yaml,
				"      - {host}:{container}:ro",
				host = gh.host_path.as_str(),
				container = GH_CONFIG_CONTAINER_PATH,
			);
		}
	}
	// Collect every env entry first so we can emit one
	// `environment:` block (or none). Order is stable for diff-
	// friendliness: SSH agent first (existing behaviour), then the
	// four git identity vars in canonical author/committer order.
	let mut env: Vec<(&str, String)> = Vec::new();
	if options.ssh_agent.is_some() {
		env.push(("SSH_AUTH_SOCK", SSH_AGENT_CONTAINER_PATH.to_owned()));
	}
	if let Some(id) = options.git_identity {
		env.push(("GIT_AUTHOR_NAME", id.name.clone()));
		env.push(("GIT_AUTHOR_EMAIL", id.email.clone()));
		env.push(("GIT_COMMITTER_NAME", id.name.clone()));
		env.push(("GIT_COMMITTER_EMAIL", id.email.clone()));
	}
	if !env.is_empty() {
		let _ = writeln!(yaml, "    environment:");
		for (key, value) in env {
			let _ = writeln!(yaml, "      {key}: {}", quote_yaml_double(&value));
		}
	}
	// `sleep infinity` is the conventional "keep this container
	// alive so we can `docker exec` into it" command. Phase 2.1
	// will keep the same shape; routed execution attaches via
	// `docker exec`, never via the entrypoint.
	let _ = writeln!(yaml, "    command: [\"sleep\", \"infinity\"]");
	let _ = writeln!(yaml);

	let _ = writeln!(yaml, "x-moon:");
	// The "which service do new terminals attach to?" key. Single
	// service today; 2.4 promotes this to a user-pickable default.
	let _ = writeln!(yaml, "  shell-service: dev");

	ComposeRender { yaml }
}

#[cfg(test)]
mod tests {
	use camino::Utf8PathBuf;

	use super::*;
	use crate::project::project_name_for_id;

	fn project() -> ProjectName {
		project_name_for_id("default").unwrap()
	}

	fn mount(host: &str, name: &str) -> BoundMount {
		BoundMount {
			host_path: Utf8PathBuf::from(host),
			mount_name: name.to_owned(),
		}
	}

	#[test]
	fn no_folders_renders_empty_volumes_list() {
		let project = project();
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[],
			ssh_agent: None,
			git_identity: None,
			gh_config: None,
		});

		assert!(render.yaml.contains("name: moon-ws-default"));
		assert!(render.yaml.contains("    volumes:\n      []"));
		// Workspace compose no longer pulls in project services —
		// they're managed per-folder now.
		assert!(!render.yaml.contains("include:"));
		// No agent forward and no git identity → no environment
		// block on the dev service at all.
		assert!(!render.yaml.contains("    environment:"));
		assert!(!render.yaml.contains("SSH_AUTH_SOCK"));
		assert!(!render.yaml.contains("GIT_AUTHOR"));
	}

	#[test]
	fn bound_folders_render_as_volume_mounts_under_slash_workspace() {
		let project = project();
		let mounts = [
			mount("/home/me/code/moon-landing", "moon-landing"),
			mount("/home/me/code/moon-ide", "moon-ide"),
		];
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &mounts,
			ssh_agent: None,
			git_identity: None,
			gh_config: None,
		});

		assert!(render
			.yaml
			.contains("- /home/me/code/moon-landing:/workspace/moon-landing"));
		assert!(render.yaml.contains("- /home/me/code/moon-ide:/workspace/moon-ide"));
		assert!(render.yaml.contains("working_dir: /workspace"));
	}

	#[test]
	fn output_is_deterministic_for_same_input() {
		let project = project();
		let mounts = [mount("/home/me/code/moon-landing", "moon-landing")];
		let opts = ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &mounts,
			ssh_agent: None,
			git_identity: None,
			gh_config: None,
		};
		let a = generate_compose(opts.clone());
		let b = generate_compose(opts);
		assert_eq!(a, b);
	}

	#[test]
	fn dev_image_override_lands_in_output() {
		// Once we publish, callers will pass the registry tag.
		let project = project();
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "huggingface/moon-base:0.1",
			bound_mounts: &[mount("/x", "x")],
			ssh_agent: None,
			git_identity: None,
			gh_config: None,
		});
		assert!(render.yaml.contains("image: huggingface/moon-base:0.1"));
	}

	#[test]
	fn project_name_lands_in_output() {
		let project = project_name_for_id("scratch").unwrap();
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[],
			ssh_agent: None,
			git_identity: None,
			gh_config: None,
		});
		assert!(render.yaml.contains("name: moon-ws-scratch"));
	}

	#[test]
	fn ssh_agent_forward_emits_volume_and_environment_block() {
		let project = project();
		let agent = SshAgentForward {
			host_socket: Utf8PathBuf::from("/tmp/ssh-XXXX/agent.42"),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[mount("/home/me/code/moon-ide", "moon-ide")],
			ssh_agent: Some(&agent),
			git_identity: None,
			gh_config: None,
		});

		assert!(render
			.yaml
			.contains("- /tmp/ssh-XXXX/agent.42:/run/host-services/ssh-auth.sock"));
		assert!(render
			.yaml
			.contains("SSH_AUTH_SOCK: \"/run/host-services/ssh-auth.sock\""));
		// The bound-folder mount still lands above the agent mount.
		assert!(render.yaml.contains("- /home/me/code/moon-ide:/workspace/moon-ide"));
	}

	#[test]
	fn ssh_agent_forward_renders_with_no_bound_folders() {
		// Pre-opt-in shape: no folders bound yet but the agent
		// is still available — the renderer must not regress to
		// `volumes: []` and drop the agent mount.
		let project = project();
		let agent = SshAgentForward {
			host_socket: Utf8PathBuf::from("/run/user/1000/keyring/ssh"),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[],
			ssh_agent: Some(&agent),
			git_identity: None,
			gh_config: None,
		});

		assert!(!render.yaml.contains("    volumes:\n      []"));
		assert!(render
			.yaml
			.contains("- /run/user/1000/keyring/ssh:/run/host-services/ssh-auth.sock"));
		assert!(render
			.yaml
			.contains("SSH_AUTH_SOCK: \"/run/host-services/ssh-auth.sock\""));
	}

	#[test]
	fn git_identity_emits_author_and_committer_env_vars() {
		let project = project();
		let identity = HostGitIdentity {
			name: "Eli Smith".into(),
			email: "eli@example.com".into(),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[mount("/home/me/code/moon-ide", "moon-ide")],
			ssh_agent: None,
			git_identity: Some(&identity),
			gh_config: None,
		});

		assert!(
			render.yaml.contains("    environment:"),
			"expected environment block, got:\n{}",
			render.yaml
		);
		assert!(render.yaml.contains("GIT_AUTHOR_NAME: \"Eli Smith\""));
		assert!(render.yaml.contains("GIT_AUTHOR_EMAIL: \"eli@example.com\""));
		assert!(render.yaml.contains("GIT_COMMITTER_NAME: \"Eli Smith\""));
		assert!(render.yaml.contains("GIT_COMMITTER_EMAIL: \"eli@example.com\""));
	}

	#[test]
	fn git_identity_and_ssh_agent_share_environment_block() {
		let project = project();
		let agent = SshAgentForward {
			host_socket: Utf8PathBuf::from("/run/user/1000/keyring/ssh"),
		};
		let identity = HostGitIdentity {
			name: "Eli".into(),
			email: "eli@example.com".into(),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[],
			ssh_agent: Some(&agent),
			git_identity: Some(&identity),
			gh_config: None,
		});

		// One environment block, both keys inside it. Stable order
		// (SSH first, then identity in author/committer order).
		let block_start = render.yaml.find("    environment:\n").expect("env block");
		let body = &render.yaml[block_start..];
		assert!(body.starts_with("    environment:\n      SSH_AUTH_SOCK: "));
		assert!(body.contains("GIT_AUTHOR_NAME: \"Eli\""));
		// Only one `environment:` block exists (regression against
		// future code re-emitting it for the second feature).
		assert_eq!(render.yaml.matches("    environment:\n").count(), 1);
	}

	#[test]
	fn gh_config_mount_renders_read_only_volume() {
		let project = project();
		let gh = GhConfigMount {
			host_path: Utf8PathBuf::from("/home/me/.config/gh"),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[mount("/home/me/code/moon-ide", "moon-ide")],
			ssh_agent: None,
			git_identity: None,
			gh_config: Some(&gh),
		});

		assert!(
			render.yaml.contains("- /home/me/.config/gh:/home/dev/.config/gh:ro"),
			"got:\n{}",
			render.yaml
		);
	}

	#[test]
	fn gh_config_mount_renders_with_no_bound_folders_or_agent() {
		let project = project();
		let gh = GhConfigMount {
			host_path: Utf8PathBuf::from("/home/me/.config/gh"),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[],
			ssh_agent: None,
			git_identity: None,
			gh_config: Some(&gh),
		});

		assert!(!render.yaml.contains("    volumes:\n      []"));
		assert!(
			render.yaml.contains("- /home/me/.config/gh:/home/dev/.config/gh:ro"),
			"got:\n{}",
			render.yaml
		);
	}

	#[test]
	fn git_identity_escapes_quote_and_backslash_in_name() {
		let project = project();
		let identity = HostGitIdentity {
			name: "Eli \"the\\test\" Smith".into(),
			email: "eli@example.com".into(),
		};
		let render = generate_compose(ComposeRenderOptions {
			project: &project,
			dev_image: "moon-base:dev",
			bound_mounts: &[],
			ssh_agent: None,
			git_identity: Some(&identity),
			gh_config: None,
		});
		// Double-quoted scalar with `"` → `\"` and `\` → `\\`.
		assert!(
			render
				.yaml
				.contains("GIT_AUTHOR_NAME: \"Eli \\\"the\\\\test\\\" Smith\""),
			"got:\n{}",
			render.yaml
		);
	}
}
